mapper.select:
WITH 상담사순서 AS ( SELECT 아이디, 이름, 지점, 조회순서 AS 순서 FROM J_참여자관리_로그인정보 WHERE 지점 = #{branch} ) SELECT ISNULL(A.이름, B.이름) AS counselorName, ISNULL(A.초기상담년도, 0) AS registYear, ISNULL(A.지점, B.지점) AS branch, ISNULL(A.취소자, 0) AS cancelCount, ISNULL(A.전체참여자, 0) AS totalParticipants, ISNULL(A.현진행자, 0) AS currentProgress, ISNULL(0, 0) AS thirdStageCount, ISNULL(A.종료자, 0) AS completedCount, ISNULL(A.중단자, 0) AS discontinuedCount, ISNULL(A.성과불인정취업, 0) AS nonApprovedEmployment, ISNULL(A.성과인정취업, 0) AS approvedEmployment, ISNULL(A.전체취업자, 0) AS totalEmployment, ISNULL(A.알선취업자, 0) AS referralEmployment, ISNULL(A.나은일자리, 0) AS betterJobCount, ISNULL(A.조기취업자, 0) AS earlyEmployment, ISNULL(A.고용유지, 0) AS employmentRetention, ISNULL(A.IAP수립1달, 0) AS iapEstablishMonth, ISNULL(A.인센발생, 0) AS incentiveOccurred, ISNULL(A.인센미발생, 0) AS incentiveNotOccurred, ISNULL(A.평가취업률, 0) AS evaluationEmploymentRate, ISNULL(A.알선취업률, 0) AS referralEmploymentRate, ISNULL(A.나은일자리비율, 0) AS betterJobRate, ISNULL(A.고용유지율, 0) AS retentionRate, ISNULL(A.조기취업자비율, 0) AS earlyEmploymentRate, ISNULL(A.취업인센티브발생율, 0) AS incentiveOccurrenceRate FROM 진행현황 A RIGHT JOIN 상담사순서 B ON B.아이디 = A.전담자_계정 AND A.초기상담년도 = #{year} AND A.지점 = #{branch} WHERE B.아이디 IN
#{userId}
ORDER BY B.순서 ASC

SELECT SUM(IIF(참여유형 = '1' , 1, 0)) AS type1,
       SUM(IIF(참여유형 = '2' , 1, 0)) AS type2
FROM J_참여자관리
WHERE 진행단계 <> ''
  AND 진행단계 <> '취소'
  AND 참여유형 <> '이관'
  AND 지점 = #{branch}
  AND YEAR(IIF(초기상담일 = '1900-01-01' , 등록일, ISNULL(초기상담일, ''))) = #{year}
  AND IIF(초기상담일 = '1900-01-01' , 등록일, ISNULL(초기상담일, '')) >= #{startDate}
  AND IIF(초기상담일 = '1900-01-01' , 등록일, ISNULL(초기상담일, '')) <= #{endDate}
  AND (전담자_계정 IN

    #{userId}

)

SELECT A.이름 counselorName, A.아이디 UserID, ISNULL(C.금일일반취업, 0) memberTodayEmployment, ISNULL(C.금일알선취업, 0) memberTodayPlacement, ISNULL(C.금주일반취업, 0) memberToWeekEmployment, ISNULL(C.금주알선취업, 0) memberToWeekPlacement, ISNULL(C.금월일반취업, 0) memberToMonthEmployment, ISNULL(C.금월알선취업, 0) memberToMonthPlacement, ISNULL(C.금년일반취업, 0) memberToYearEmployment, ISNULL(C.금년알선취업, 0) memberToYearPlacement, ISNULL(C.업무보고일, '1900-01-01') endUpdateStatus FROM J_참여자관리_로그인정보 A LEFT JOIN ( -- 아이디별 최신 업무보고 데이터만 추출 SELECT *, ROW_NUMBER() OVER (PARTITION BY 지점, 아이디 ORDER BY 업무보고일 DESC) as rn FROM J_참여자관리_일일업무보고 ) C ON A.지점 = C.지점 AND A.아이디 = C.아이디 AND C.rn = 1 WHERE A.지점=#{branch} AND (A.아이디 IN
#{userId}
) ORDER BY A.조회순서

mapper.update:
UPDATE J_참여자관리_지점
SET
    유형1=#{branchType1},
    유형2=#{branchType2}
WHERE 지점 = #{branch}
